patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index 703065280096..45b515458211 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -3076,7 +3076,21 @@ Value *InstCombinerImpl::foldAndOrOfICmps(ICmpInst *LHS, ICmpInst *RHS,
   Value *LHS1 = LHS->getOperand(1), *RHS1 = RHS->getOperand(1);
   const APInt *LHSC = nullptr, *RHSC = nullptr;
   match(LHS1, m_APInt(LHSC));
-  match(RHS1, m_APInt(RHSC));
+  // (icmp ult (add A, B), A) | (icmp ult (add A, B), B) -> (icmp ult (add A, B), A)
+  // (icmp ugt (add A, B), A) & (icmp ugt (add A, B), B) -> (icmp ugt (add A, B), A)
+  // These patterns check for unsigned overflow of addition. Both comparisons are
+  // equivalent since overflow of A+B happens iff the result is less than A or
+  // equivalently less than B.
+  if (LHS0 == RHS0 && PredL == PredR &&
+      (IsAnd ? PredL == ICmpInst::ICMP_UGT : PredL == ICmpInst::ICMP_ULT)) {
+    Value *AddOp0, *AddOp1;
+    if (match(LHS0, m_c_Add(m_Value(AddOp0), m_Value(AddOp1)))) {
+      if ((LHS1 == AddOp0 && RHS1 == AddOp1) ||
+          (LHS1 == AddOp1 && RHS1 == AddOp0)) {
+        return LHS;
+      }
+    }
+  }

   // (icmp1 A, B) | (icmp2 A, B) --> (icmp3 A, B)
   // (icmp1 A, B) & (icmp2 A, B) --> (icmp3 A, B)
